INSERT INTO `karaoke_shop` VALUES (1,'Ha Dong, Ha Noi','Ha Noi','Level\'s most acclaimed karaoke destination. Eight meticulously designed private rooms with state-of-the-art acoustics, a curated cocktail bar, and song libraries spanning 80,000+ titles.','data:image/jpeg;base64,',50,'Karaoke Level','Mon–Sun: 12:00 PM – 5:00 AM','+81 3-1234-5679',3,2,'ACTIVE'),(2,'15 Orchard Road, Singapore','Singapore','A welcoming karaoke venue in the heart of Orchard, perfect for families and groups. Spacious rooms with modern equipment and a wide selection of Asian and Western hits.','data:image/jpeg;base64,',25,'Melody House','Mon–Sun: 11:00 AM – 2:00 AM','+65 6234-5678',NULL,NULL,'ACTIVE'),(3,'88 Itaewon-ro, Yongsan-gu, Seoul','Seoul','Seoul\'s most sophisticated late-night karaoke lounge. Dark, atmospheric interiors with premium sound systems, a curated spirits menu, and exclusive K-Pop performance packages.','data:image/jpeg;base64,',30,'Noir Sessions','','+82 2-3456-7891',NULL,NULL,'ACTIVE'),(4,'45 Queen St, Melbourne','Melbourne','Melbourne\'s hidden gem for karaoke enthusiasts. Rooftop terrace access, all-inclusive snack packages, and dedicated birthday celebration setups available.\n','data:image/jpeg;base64,',21,'Studio Serenade','Tue–Sun: 5:00 PM – 1:00 AM','+61 3-9012-3456',NULL,NULL,'ACTIVE');
INSERT INTO `karaoke_shop` VALUES (5,'321 Sukhumvit Rd, Bangkok','Bangkok','The best value karaoke experience in Bangkok. Bright, clean rooms with a vast selection of Thai, English, Chinese, and Japanese songs. Perfect for large groups','data:image/jpeg;base64,',15,'Vocal Vault','','+66 2-123-4567',NULL,NULL,'ACTIVE'),(6,'Ha Noi','Ha Noi','','data:image/jpeg;base64,',10,'quang','','4567890',NULL,NULL,'ACTIVE'),(7,'Ha Noi','Ha Noi','','data:image/x-icon;base64,',30,'test','8:00-23:00','34567890',0,0,'ACTIVE');
